import sys
import os
import json
import ast
import re

BUILTINS = set(dir(__builtins__)) if isinstance(__builtins__, dict) else set(dir(__builtins__))
BUILTINS.update(['__name__', '__file__', '__doc__', '__builtins__', '__spec__', '__loader__', '__package__',
                  'print', 'len', 'range', 'int', 'str', 'float', 'list', 'dict', 'set', 'tuple',
                  'bool', 'type', 'None', 'True', 'False', 'isinstance', 'issubclass', 'hasattr',
                  'getattr', 'setattr', 'delattr', 'super', 'property', 'staticmethod', 'classmethod',
                  'open', 'input', 'map', 'filter', 'zip', 'enumerate', 'sorted', 'reversed',
                  'min', 'max', 'sum', 'abs', 'round', 'any', 'all', 'next', 'iter',
                  'Exception', 'BaseException', 'ValueError', 'TypeError', 'KeyError', 'IndexError',
                  'AttributeError', 'ImportError', 'OSError', 'IOError', 'FileNotFoundError',
                  'RuntimeError', 'StopIteration', 'NotImplementedError', 'ZeroDivisionError',
                  'NameError', 'ModuleNotFoundError', 'OverflowError', 'RecursionError'])

def analyze(code_text, strict=False):
    issues = []
    lines = code_text.splitlines()

    # Check syntax first
    try:
        tree = ast.parse(code_text)
    except SyntaxError as e:
        issues.append({'line': e.lineno or 1, 'severity': 'error', 'message': f'Syntax error: {e.msg}'})
        return issues

    # Collect all defined names and imported names
    defined_names = set()
    imported_names = {}
    used_names = set()
    function_defs = []

    class NameCollector(ast.NodeVisitor):
        def __init__(self):
            self.scope_stack = [set()]

        def visit_Import(self, node):
            for alias in node.names:
                name = alias.asname if alias.asname else alias.name.split('.')[0]
                imported_names[name] = node.lineno
                defined_names.add(name)
            self.generic_visit(node)

        def visit_ImportFrom(self, node):
            for alias in node.names:
                name = alias.asname if alias.asname else alias.name
                if name == '*':
                    continue
                imported_names[name] = node.lineno
                defined_names.add(name)
            self.generic_visit(node)

        def visit_FunctionDef(self, node):
            defined_names.add(node.name)
            function_defs.append(node)
            for arg in node.args.args + node.args.posonlyargs + node.args.kwonlyargs:
                defined_names.add(arg.arg)
            if node.args.vararg:
                defined_names.add(node.args.vararg.arg)
            if node.args.kwarg:
                defined_names.add(node.args.kwarg.arg)
            self.generic_visit(node)

        visit_AsyncFunctionDef = visit_FunctionDef

        def visit_ClassDef(self, node):
            defined_names.add(node.name)
            self.generic_visit(node)

        def visit_Name(self, node):
            if isinstance(node.ctx, (ast.Load, ast.Del)):
                used_names.add(node.id)
            elif isinstance(node.ctx, ast.Store):
                defined_names.add(node.id)
            self.generic_visit(node)

        def visit_Global(self, node):
            for name in node.names:
                defined_names.add(name)
            self.generic_visit(node)

        def visit_For(self, node):
            if isinstance(node.target, ast.Name):
                defined_names.add(node.target.id)
            elif isinstance(node.target, ast.Tuple):
                for elt in node.target.elts:
                    if isinstance(elt, ast.Name):
                        defined_names.add(elt.id)
            self.generic_visit(node)

        def visit_With(self, node):
            for item in node.items:
                if item.optional_vars and isinstance(item.optional_vars, ast.Name):
                    defined_names.add(item.optional_vars.id)
            self.generic_visit(node)

        def visit_ExceptHandler(self, node):
            if node.name:
                defined_names.add(node.name)
            self.generic_visit(node)

    collector = NameCollector()
    collector.visit(tree)

    # Check for unused imports
    for name, lineno in imported_names.items():
        if name not in used_names and not name.startswith('_'):
            issues.append({'line': lineno, 'severity': 'warning', 'message': f"Unused import: '{name}'"})

    # Check for long functions
    for func in function_defs:
        end_line = getattr(func, 'end_lineno', None)
        if end_line:
            length = end_line - func.lineno
            threshold = 30 if strict else 50
            if length > threshold:
                issues.append({'line': func.lineno, 'severity': 'warning',
                               'message': f"Function '{func.name}' is {length} lines long (threshold: {threshold})"})

        # Check for missing docstring
        if strict and func.body:
            first = func.body[0]
            if not (isinstance(first, ast.Expr) and isinstance(first.value, (ast.Str, ast.Constant))):
                issues.append({'line': func.lineno, 'severity': 'info',
                               'message': f"Function '{func.name}' is missing a docstring"})

    # Line-level checks
    for i, line in enumerate(lines, 1):
        # Line length
        if len(line) > (88 if strict else 120):
            issues.append({'line': i, 'severity': 'info',
                           'message': f'Line is {len(line)} chars (limit: {88 if strict else 120})'})
        # Trailing whitespace
        if strict and line.rstrip() != line and line.strip():
            issues.append({'line': i, 'severity': 'info', 'message': 'Trailing whitespace'})
        # TODO/FIXME/HACK markers
        if re.search(r'#\s*(TODO|FIXME|HACK|XXX)', line, re.IGNORECASE):
            issues.append({'line': i, 'severity': 'info',
                           'message': f'Contains TODO/FIXME marker'})

    # Check for bare except
    for node in ast.walk(tree):
        if isinstance(node, ast.ExceptHandler) and node.type is None:
            issues.append({'line': node.lineno, 'severity': 'warning', 'message': 'Bare except clause (catches all exceptions including SystemExit, KeyboardInterrupt)'})

    # Sort by line number
    issues.sort(key=lambda x: x['line'])
    return issues

def score_from_issues(issues, total_lines):
    if total_lines == 0:
        return 10.0
    penalty = 0
    for issue in issues:
        if issue['severity'] == 'error':
            penalty += 3.0
        elif issue['severity'] == 'warning':
            penalty += 1.0
        else:
            penalty += 0.3
    # Normalize: start at 10, subtract penalties scaled by file size
    score = 10.0 - (penalty / max(total_lines / 10, 1))
    return round(max(0.0, min(10.0, score)), 1)

def main():
    inputs = json.loads(os.environ.get('SKILL_INPUTS', '{}'))
    code_path = inputs.get('codePath', '')
    strict = inputs.get('strict', False)

    if not code_path or not os.path.exists(code_path):
        print(json.dumps({'issues': [{'line': 0, 'severity': 'error', 'message': f'File not found: {code_path}'}], 'score': 0}))
        return

    with open(code_path, 'r', encoding='utf-8') as f:
        code_text = f.read()

    issues = analyze(code_text, strict)
    total_lines = len(code_text.splitlines())
    score = score_from_issues(issues, total_lines)

    print(json.dumps({'issues': issues, 'score': score}))

if __name__ == '__main__':
    main()
